const body = $input.first().json.body || $input.first().json;
const entry = (body.entry && body.entry[0]) || {};
const change = (entry.changes && entry.changes[0]) || {};
const value = change.value || {};
const messages = value.messages || [];
if (!messages.length) {
  return [{ json: { skip: true } }];
}
const msg = messages[0];
const usuario_id = msg.from;
let tipo = 'unsupported';
let texto = '';
let lat = null;
let lon = null;
if (msg.location) {
  tipo = 'location';
  lat = msg.location.latitude;
  lon = msg.location.longitude;
} else if (msg.text) {
  tipo = 'text';
  texto = (msg.text.body || '').toLowerCase().trim();
}
return [{ json: { skip: false, usuario_id, tipo, texto, lat, lon, raw: msg } }];

const incoming = $('Parse Message').first().json;
const userLoc = $input.first().json || {};
const hasLoc = !!(userLoc.lat && userLoc.lon);
const texto = incoming.texto || '';
const tipo = incoming.tipo;
const saludos = ['hola','hi','hello','buenos dias','buenas tardes','buenas','buenas noches'];
const noSabe = ['no se','no sé','no idea','no tengo idea','que recomiendas','qué recomiendas','recomiendame','recomiéndame','sugiere','que hay','qué hay','variedad'].some(p => texto.includes(p));
const pideActualizar = ['actualizar ubicacion','actualizar ubicación','nueva ubicacion','nueva ubicación','cambiar ubicacion','cambiar ubicación'].some(p => texto.includes(p));

const etiquetas = {
  'choripán': ['choripán','choripan','chori'],
  'hamburguesa': ['hamburguesa','hamburguesas','burger','hamburgues'],
  'pizza': ['pizza','pizzas','pizzería'],
  'taco': ['taco','tacos','taquitos'],
  'sushi': ['sushi','rolls','sashimi'],
  'arepa': ['arepa','arepas'],
  'empanada': ['empanada','empanadas'],
  'pasta': ['pasta','pastas','espagueti','lasaña','lasagna'],
  'postre': ['postre','postres','dulce','helado','torta'],
  'café': ['café','cafe','capuchino','expreso']
};
let etiquetaDetectada = null;
for (const [k, arr] of Object.entries(etiquetas)) {
  if (arr.some(p => texto.includes(p))) { etiquetaDetectada = k; break; }
}

const zonas = {
  'norte': ['norte','granada','chipichape'],
  'sur': ['sur','ciudad jardín','ciudad jardin','limonar'],
  'centro': ['centro','san antonio'],
  'oeste': ['oeste','normandía','normandia'],
  'oriente': ['oriente','este']
};
let zonaDetectada = null;
for (const [k, arr] of Object.entries(zonas)) {
  if (arr.some(p => texto.includes(p))) { zonaDetectada = k; break; }
}
const pideCerca = ['cerca','cercano','cercana','cercanía','próximo','proximo','próxima','proxima'].some(p => texto.includes(p));

let intent = 'consulta';
if (tipo === 'location') intent = 'ubicacion_recibida';
else if (saludos.includes(texto)) intent = 'saludo';
else if (pideActualizar) intent = 'actualizar_ubicacion';
else if (!hasLoc) intent = 'pedir_ubicacion';

return [{
  json: {
    usuario_id: incoming.usuario_id,
    tipo,
    texto,
    intent,
    hasLoc,
    ubicacion_usuario: hasLoc ? { lat: userLoc.lat, lon: userLoc.lon } : null,
    noSabe,
    etiquetaDetectada,
    zonaDetectada,
    pideCerca
  }
}];

// Receives the array of restaurants in input + intent context from earlier nodes.
const lista = $input.first().json.data || [];
const ctx = $('Detect Intent').first().json;
const u = ctx.ubicacion_usuario;

async function osrm(lat1, lon1, lat2, lon2) {
  const url = `http://router.project-osrm.org/route/v1/driving/${lon1},${lat1};${lon2},${lat2}?overview=false`;
  try {
    const r = await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 8000 });
    if (!r || !r.routes || !r.routes.length) return null;
    return r.routes[0].distance / 1000;
  } catch (e) { return null; }
}

const withDist = [];
for (const r of lista) {
  const ub = r.ubicacion || {};
  const lat = ub.lat;
  const lon = ub.lng || ub.lon;
  let dist = null;
  if (lat && lon && u) {
    dist = await osrm.call(this, u.lat, u.lon, lat, lon);
  }
  withDist.push({ ...r, distancia_real_km: dist == null ? null : Math.round(dist * 1000) / 1000 });
}
withDist.sort((a, b) => (a.distancia_real_km ?? 9999) - (b.distancia_real_km ?? 9999));

let filtrados = withDist.slice();
let contexto = 'Usuario con ubicación disponible';

if (!ctx.noSabe) {
  if (ctx.etiquetaDetectada) {
    const tag = ctx.etiquetaDetectada;
    let f = filtrados.filter(r => Array.isArray(r.subtipo) && r.subtipo.some(s => String(s).toLowerCase().includes(tag)));
    if (!f.length) f = withDist.filter(r => (r.tipo || '').toLowerCase().includes(tag));
    filtrados = f;
    contexto = `Usuario busca ${tag}`;
  }
  if (ctx.zonaDetectada) {
    filtrados = filtrados.filter(r => (r.zona || '').toLowerCase().includes(ctx.zonaDetectada));
    contexto += ` en ${ctx.zonaDetectada}`;
  }
  if (ctx.pideCerca) {
    filtrados = filtrados.filter(r => (r.distancia_real_km ?? 999) <= 2.0);
    contexto += ' (muy cercanos)';
  }
}

const top = (filtrados.length ? filtrados : withDist).slice(0, 15);

function fmtDist(km) {
  if (km == null) return 'Distancia no disponible';
  if (km < 1) return `A ${Math.round(km * 1000)} m`;
  if (km < 10) return `A ${km.toFixed(2)} km`;
  return `A ${km.toFixed(1)} km`;
}
function fmtRedes(redes) {
  if (!redes) return 'No disponibles';
  const out = [];
  if (redes.facebook && redes.facebook.startsWith('http')) out.push(`📘 [Facebook](${redes.facebook})`);
  if (redes.instagram && redes.instagram.startsWith('http')) out.push(`📷 [Instagram](${redes.instagram})`);
  if (redes.tiktok && redes.tiktok.startsWith('http')) out.push(`🎵 [TikTok](${redes.tiktok})`);
  return out.length ? out.join(' | ') : 'No disponibles';
}
const infoBlocks = top.map(r => {
  const ub = r.ubicacion || {};
  const lat = ub.lat, lon = ub.lng || ub.lon;
  const mapa = ub.mapa_url || (lat && lon ? `https://www.google.com/maps?q=${lat},${lon}` : null);
  const dir = mapa ? `🗺️ [Ver en Google Maps](${mapa})` : (ub.direccion || 'No disponible');
  const sub = Array.isArray(r.subtipo) && r.subtipo.length ? `• 🏷️ Especialidad: ${r.subtipo.slice(0,3).join(', ')}\n` : '';
  return `\n🍽️ ${r.nombre || 'Sin nombre'}\n• 🏷️ Tipo: ${r.tipo || 'No especificado'}\n${sub}• 📍 Zona: ${r.zona || 'No especificada'}\n• 💰 Precio: ${r.precio || 'No especificado'}\n• 📞 Contacto: ${r.contacto || 'No disponible'}\n• 🌐 Redes: ${fmtRedes(r.redes)}\n• 🗺️ Dirección: ${dir}\n• 📏 ${fmtDist(r.distancia_real_km)}\n`;
});

return [{
  json: {
    usuario_id: ctx.usuario_id,
    mensaje_usuario: ctx.texto,
    contexto,
    ubicacion_usuario: u,
    restaurantes_top: top,
    restaurantes_texto: infoBlocks.join('\n'),
    sin_resultados: filtrados.length === 0
  }
}];

