const ai = $input.first().json;
const prev = $('OSRM + Filter').first().json;
let respuesta = '';
try {
  respuesta = ai.choices[0].message.content.trim();
} catch (e) {
  respuesta = '🍽️ Te recomiendo estas opciones cercanas:\n' + (prev.restaurantes_texto || '');
}
return [{ json: { to: prev.usuario_id, usuario_id: prev.usuario_id, mensaje_usuario: prev.mensaje_usuario, respuesta } }];
